package com.hospital.management.util;import java.math.*;import java.time.*;/** Calculates room charges where every started 24-hour period is a full day. */public class AdmissionChargeCalculator{public long calculateChargeableDays(LocalDateTime a,LocalDateTime d){if(a==null||d==null||d.isBefore(a))throw new IllegalArgumentException("Invalid admission interval");long seconds=Duration.between(a,d).getSeconds();return Math.max(1,(seconds+86399)/86400);}public BigDecimal calculateRoomCharge(LocalDateTime a,LocalDateTime d,BigDecimal rate){if(rate==null||rate.signum()<0)throw new IllegalArgumentException("Invalid daily rate");return rate.multiply(BigDecimal.valueOf(calculateChargeableDays(a,d))).setScale(2,RoundingMode.HALF_UP);}}
